async ({ data, cwd, join, importModule, ok, fail }) => {
  const { cssFiles, contentGlobs, safelists, selectorPrefix } = data;
  if (!Array.isArray(cssFiles) || !Array.isArray(contentGlobs) || !Array.isArray(safelists) || typeof selectorPrefix !== "string") {
    return fail("purgecss config is invalid\n");
  }
  const safelistRe = safelists.map((pattern: string) => new RegExp(pattern));
  const safePattern = safelists.length > 0 ? new RegExp(safelists.join("|")) : null;
  const purgeCssModule = await importModule("purgecss") as {
    PurgeCSS: new () => {
      purge: (options: {
        css: string[];
        content: string[];
        rejected: boolean;
        safelist: { greedy: RegExp[] };
      }) => Promise<Array<{ rejected?: string[] }>>;
    };
  };
  const [result] = await new purgeCssModule.PurgeCSS().purge({
    css: cssFiles.map((file: string) => join(cwd, file)),
    content: contentGlobs.map((glob: string) => join(cwd, glob)),
    rejected: true,
    safelist: { greedy: safelistRe }
  });
  const rejected = Array.isArray(result?.rejected) ? result.rejected : [];
  const unused = rejected.filter((selector: string) => selector.startsWith(selectorPrefix) && !(safePattern?.test(selector) ?? false));
  if (unused.length === 0) return ok("no unused CSS selectors found\n");
  return fail(unused.map((selector: string) => "  unused: " + selector).join("\n") + "\nfound " + unused.length + " unused CSS selector(s)\n");
}

