({ command, data, displayOutput, existsSync, helpers, readFileSync, resolveTokenString }) => {
  const readPath = (value: unknown) => typeof value === "string" ? resolveTokenString(value) : "";
  const toNumber = (value: unknown, fallback: number) => {
    if (typeof value === "number" && Number.isFinite(value)) return value;
    if (typeof value === "string") {
      const parsed = Number.parseFloat(resolveTokenString(value));
      if (Number.isFinite(parsed)) return parsed;
    }
    return fallback;
  };
  const attrs = (raw: string) => Object.fromEntries(Array.from(raw.matchAll(/(\w+)="([^"]*)"/g)).flatMap((match) => match[1] ? [[match[1], match[2] ?? ""]] : []));
  const formatTest = (test: { file?: string; line?: string; message?: string; name: string; suite?: string }) => `${test.file ?? "unknown-file"}${test.line ? `:${test.line}` : ""} - ${test.suite ? `${test.suite} > ` : ""}${test.name}${test.message ? ` [${test.message}]` : ""}`;
  const reportPath = readPath(data.reportPath);
  const coveragePath = readPath(data.coveragePath);
  const coverageLabel = typeof data.coverageLabel === "string" ? data.coverageLabel : "coverage";
  const coverageExcludedFiles = new Set(Array.isArray(data.coverageExcludedFiles) ? data.coverageExcludedFiles.filter((value): value is string => typeof value === "string") : []);
  const coverageThreshold = toNumber(data.coverageThreshold, 85);
  const messages: Array<{ text: string; tone?: "fail" | "warn" }> = [];
  const sections: Array<{ items: string[]; title: string; tone?: "fail" | "warn" }> = [];
  const extraChecks: Array<{ details: string; label: string; status: "fail" | "pass" }> = [];
  let passed = 0;
  let failed = 0;
  let skipped = 0;
  let status: "fail" | "pass" = command.exitCode === 0 ? "pass" : "fail";

  if (!reportPath || !existsSync(reportPath)) {
    messages.push({ text: `Report file not found: ${reportPath || "(unset)"}`, tone: "fail" });
    status = "fail";
  } else {
    const report = readFileSync(reportPath, "utf8");
    const suitesAttrs = attrs(report.match(/<testsuites\b([^>]*)>/)?.[1] ?? "");
    const totalTests = Number.parseInt(suitesAttrs.tests ?? "0", 10);
    failed = Number.parseInt(suitesAttrs.failures ?? "0", 10);
    skipped = Number.parseInt(suitesAttrs.skipped ?? "0", 10);
    passed = Math.max(0, totalTests - failed - skipped);

    if (failed > 0 || skipped > 0) {
      const failedTests: string[] = [];
      const skippedTests: string[] = [];
      for (const match of report.matchAll(/<testcase\b([^>]*?)(?:\/>|>([\s\S]*?)<\/testcase>)/g)) {
        const test = attrs(match[1] ?? "");
        const body = match[2] ?? "";
        if (!/<skipped\b/.test(body) && !body.includes("<failure") && !body.includes("<error")) {
          continue;
        }
        const formatted = formatTest({
          file: test.file,
          line: test.line,
          message: attrs(body.match(/<(?:failure|error)\b([^>]*)>/)?.[1] ?? "").message,
          name: test.name ?? "(unnamed test)",
          suite: test.classname,
        });
        if (/<skipped\b/.test(body)) {
          skippedTests.push(formatted);
          continue;
        }
        failedTests.push(formatted);
      }
      if (failedTests.length > 0) {
        sections.push({ items: failedTests, title: "Failed tests", tone: "fail" });
        status = "fail";
      }
      if (skippedTests.length > 0) {
        sections.push({ items: skippedTests, title: "Skipped tests", tone: "warn" });
      }
    }
  }

  if (!coveragePath || !existsSync(coveragePath)) {
    messages.push({ text: `Coverage report not found: ${coveragePath || "(unset)"}`, tone: "fail" });
    extraChecks.push({ details: `0.00% (0/0) · threshold ${coverageThreshold.toFixed(1)}%`, label: coverageLabel, status: "fail" });
  } else {
    let activeFile = "";
    let includeActiveFile = false;
    let covered = 0;
    let found = 0;
    for (const line of readFileSync(coveragePath, "utf8").split(/\r?\n/)) {
      if (line.startsWith("SF:")) {
        activeFile = line.slice(3);
        includeActiveFile = !coverageExcludedFiles.has(activeFile);
        continue;
      }
      if (!includeActiveFile || !activeFile || !line.startsWith("DA:")) continue;
      const hitCount = Number.parseInt(line.slice(line.lastIndexOf(",") + 1), 10);
      if (!Number.isFinite(hitCount)) continue;
      found += 1;
      if (hitCount > 0) covered += 1;
    }
    const pct = found > 0 ? (covered / found) * 100 : 0;
    const coverageStatus: "fail" | "pass" = found > 0 && pct >= coverageThreshold ? "pass" : "fail";
    extraChecks.push({
      details: `${pct.toFixed(2)}% (${covered}/${found}) · threshold ${coverageThreshold.toFixed(1)}%`,
      label: coverageLabel,
      status: coverageStatus,
    });
    if (found === 0) {
      messages.push({ text: "No executable lines found in coverage report", tone: "fail" });
    }
    if (coverageStatus === "fail") {
      status = "fail";
    }
  }

  const summary = `${passed} passed · ${failed} failed · ${skipped} skipped${command.exitCode === 0 ? "" : ` · runner exit ${command.exitCode}`}`;
  return {
    extraChecks,
    messages,
    output: helpers.compactDomAssertionNoise(displayOutput),
    sections,
    status,
    summary,
  };
}

({ command, data, displayOutput, existsSync, helpers, readFileSync, resolveTokenString }) => {
  const readPath = (value: unknown) => typeof value === "string" ? resolveTokenString(value) : "";
  const toNumber = (value: unknown, fallback: number) => {
    if (typeof value === "number" && Number.isFinite(value)) return value;
    if (typeof value === "string") {
      const parsed = Number.parseFloat(resolveTokenString(value));
      if (Number.isFinite(parsed)) return parsed;
    }
    return fallback;
  };
  const parseGroupedNumber = (value: string) => Number.parseInt(value.replace(/,/g, ""), 10);
  const attrs = (raw: string) => Object.fromEntries(Array.from(raw.matchAll(/(\w+)="([^"]*)"/g)).flatMap((match) => match[1] ? [[match[1], match[2] ?? ""]] : []));
  const formatTest = (test: { file?: string; line?: string; message?: string; name: string; suite?: string }) => `${test.file ?? "unknown-file"}${test.line ? `:${test.line}` : ""} - ${test.suite ? `${test.suite} > ` : ""}${test.name}${test.message ? ` [${test.message}]` : ""}`;
  const parsePlaywrightCount = (label: string) => {
    const match = displayOutput.match(new RegExp(`(?:^|\n)\s*(\d+)\s+${label}(?:\s|$)`, "i"));
    return match ? Number.parseInt(match[1] ?? "0", 10) : 0;
  };
  const readConsoleLineCoverage = () => {
    const match = displayOutput.match(/(?:^|\n)\s*[│|]\s*Lines\s*[│|]\s*([\d.]+)\s*%\s*[│|]\s*([\d,]+)\s*[│|]\s*[\d,]+\s*[│|]\s*([\d,]+)\s*[│|]/u);
    if (!match) return null;
    const pct = Number.parseFloat(match[1] ?? "0");
    const covered = parseGroupedNumber(match[2] ?? "0");
    const found = parseGroupedNumber(match[3] ?? "0");
    if (!Number.isFinite(pct) || !Number.isFinite(covered) || !Number.isFinite(found)) {
      return null;
    }
    return { covered, found, pct };
  };
  const reportPath = readPath(data.reportPath);
  const coveragePath = readPath(data.coveragePath);
  const coverageLabel = typeof data.coverageLabel === "string" ? data.coverageLabel : "coverage";
  const coverageThreshold = toNumber(data.coverageThreshold, 0);
  const messages: Array<{ text: string; tone?: "fail" | "warn" }> = [];
  const sections: Array<{ items: string[]; title: string; tone?: "fail" | "warn" }> = [];
  const extraChecks: Array<{ details: string; label: string; status: "fail" | "pass" }> = [];
  let passed = 0;
  let failed = 0;
  let skipped = 0;
  let status: "fail" | "pass" = command.exitCode === 0 ? "pass" : "fail";

  if (!reportPath || !existsSync(reportPath)) {
    passed = parsePlaywrightCount("passed");
    failed = parsePlaywrightCount("failed");
    skipped = parsePlaywrightCount("skipped");
    if (passed === 0 && failed === 0 && skipped === 0) {
      messages.push({ text: `Report file not found: ${reportPath || "(unset)"}`, tone: "fail" });
      status = "fail";
    } else if (failed > 0) {
      status = "fail";
    }
  } else {
    const report = readFileSync(reportPath, "utf8");
    const suitesAttrs = attrs(report.match(/<testsuites\b([^>]*)>/)?.[1] ?? "");
    const totalTests = Number.parseInt(suitesAttrs.tests ?? "0", 10);
    failed = Number.parseInt(suitesAttrs.failures ?? "0", 10);
    skipped = Number.parseInt(suitesAttrs.skipped ?? "0", 10);
    passed = Math.max(0, totalTests - failed - skipped);

    if (failed > 0 || skipped > 0) {
      const failedTests: string[] = [];
      const skippedTests: string[] = [];
      for (const match of report.matchAll(/<testcase\b([^>]*?)(?:\/>|>([\s\S]*?)<\/testcase>)/g)) {
        const test = attrs(match[1] ?? "");
        const body = match[2] ?? "";
        if (!/<skipped\b/.test(body) && !body.includes("<failure") && !body.includes("<error")) {
          continue;
        }
        const formatted = formatTest({
          file: test.file,
          line: test.line,
          message: attrs(body.match(/<(?:failure|error)\b([^>]*)>/)?.[1] ?? "").message,
          name: test.name ?? "(unnamed test)",
          suite: test.classname,
        });
        if (/<skipped\b/.test(body)) {
          skippedTests.push(formatted);
          continue;
        }
        failedTests.push(formatted);
      }
      if (failedTests.length > 0) {
        sections.push({ items: failedTests, title: "Failed tests", tone: "fail" });
        status = "fail";
      }
      if (skippedTests.length > 0) {
        sections.push({ items: skippedTests, title: "Skipped tests", tone: "warn" });
      }
    }
  }

  const consoleLineCoverage = readConsoleLineCoverage();
  if (consoleLineCoverage) {
    const coverageStatus: "fail" | "pass" = consoleLineCoverage.found > 0 && consoleLineCoverage.pct >= coverageThreshold ? "pass" : "fail";
    extraChecks.push({
      details: `${consoleLineCoverage.pct.toFixed(2)}% (${consoleLineCoverage.covered}/${consoleLineCoverage.found}) · threshold ${coverageThreshold.toFixed(1)}%`,
      label: coverageLabel,
      status: coverageStatus,
    });
    if (coverageStatus === "fail") {
      status = "fail";
    }
  } else if (!coveragePath || !existsSync(coveragePath)) {
    messages.push({ text: `Coverage report not found: ${coveragePath || "(unset)"}`, tone: "fail" });
    extraChecks.push({ details: `0.00% (0/0) · threshold ${coverageThreshold.toFixed(1)}%`, label: coverageLabel, status: "fail" });
    status = "fail";
  } else {
    messages.push({ text: "Coverage summary row not found in Playwright output; falling back to raw artifact totals.", tone: "warn" });
    const rawCoverageText = readFileSync(coveragePath, "utf8");
    const rawLineCount = (rawCoverageText.match(/^DA:/gm) ?? []).length;
    const rawCoveredCount = (rawCoverageText.match(/^DA:[^,]+,[1-9]\d*$/gm) ?? []).length;
    const pct = rawLineCount > 0 ? (rawCoveredCount / rawLineCount) * 100 : 0;
    const coverageStatus: "fail" | "pass" = rawLineCount > 0 && pct >= coverageThreshold ? "pass" : "fail";
    extraChecks.push({
      details: `${pct.toFixed(2)}% (${rawCoveredCount}/${rawLineCount}) · threshold ${coverageThreshold.toFixed(1)}%`,
      label: coverageLabel,
      status: coverageStatus,
    });
    if (rawLineCount === 0) {
      messages.push({ text: "No executable lines found in coverage report", tone: "fail" });
    }
    if (coverageStatus === "fail") {
      status = "fail";
    }
  }

  const summary = `${passed} passed · ${failed} failed · ${skipped} skipped${command.exitCode === 0 ? "" : ` · runner exit ${command.exitCode}`}`;
  return {
    extraChecks,
    messages,
    output: helpers.compactDomAssertionNoise(displayOutput),
    sections,
    status,
    summary,
  };
}
